                        if (gk != null) {
                            generatedKeys = new JdbcResultSet(conn, this, command, gk, id, true, false, false);
                        }
                    }
                } finally {
                    if (!lazy) {
                        setExecutingStatement(null);
                    }
                }
            }
            return returnsResultSet;
